const today = new Date().toISOString().slice(0, 10);
const url = `https://plotlens.ai/smoke-test/${today}`;
return [{json: {smoke_url: url, smoke_notes: 'nightly smoke'}}];

const smokeUrl = $('Build Smoke URL').item.json.smoke_url;

const blocks = [
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `:rotating_light: *Outreach smoke FAILED* — manual webhook did not reach drafted status within 5 min.\nURL: \`${smokeUrl}\``
    }
  }
];

return [{
  json: {
    smoke_url: smokeUrl,
    slack_blocks: blocks,
    slack_text_fallback: `:rotating_light: Outreach smoke FAILED — ${smokeUrl} not drafted after 5 min`
  }
}];

// Fires when Trigger Discover errors at the HTTP layer (e.g. connection refused,
// DNS NXDOMAIN, TLS handshake failure). Builds a Slack alert that surfaces the
// underlying error message so an operator can diagnose without diving into n8n
// execution logs.
const smokeUrl = $('Build Smoke URL').item.json.smoke_url;
const errMsg = ($json && ($json.error || ($json.message))) || 'unknown HTTP failure';

const blocks = [
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `:rotating_light: *Outreach smoke FAILED at HTTP layer* — \`Trigger Discover\` could not reach the webhook.\nURL: \`${smokeUrl}\`\nError: \`${String(errMsg).slice(0, 500)}\``
    }
  }
];

return [{
  json: {
    smoke_url: smokeUrl,
    slack_blocks: blocks,
    slack_text_fallback: `:rotating_light: Outreach smoke HTTP failure — ${smokeUrl}`
  }
}];
